# Nginx configuration for HTTP/2 enforcement and request smuggling prevention

# Front-end listener (client-facing)
server {
    listen 443 ssl http2;  # Enable HTTP/2 for client connections
    server_name api.example.com;

    ssl_certificate /etc/nginx/ssl/cert.pem;
    ssl_certificate_key /etc/nginx/ssl/key.pem;
    ssl_protocols TLSv1.2 TLSv1.3;

    # Disable HTTP/1.0 and HTTP/1.1 to enforce HTTP/2
    # Note: This may break legacy clients
    if ($server_protocol !~ "HTTP/2.0") {
        return 426 "Upgrade Required: HTTP/2 is required";
    }

    # Request normalization to prevent smuggling
    # Reject requests with both Content-Length and Transfer-Encoding
    if ($http_transfer_encoding != "") {
        set $has_te 1;
    }
    if ($http_content_length != "") {
        set $has_cl 1;
    }
    if ($has_te = 1) {
        if ($has_cl = 1) {
            return 400 "Bad Request: Both Content-Length and Transfer-Encoding present";
        }
    }

    # Reject ambiguous Transfer-Encoding values
    if ($http_transfer_encoding ~* "chunked.*chunked|,") {
        return 400 "Bad Request: Invalid Transfer-Encoding";
    }

    # Upstream configuration (back-end communication)
    location / {
        # Use HTTP/2 or HTTP/1.1 with strict validation to back-end
        proxy_pass http://backend_servers;

        # Force HTTP/1.1 with Connection: close to prevent request pipelining
        proxy_http_version 1.1;
        proxy_set_header Connection "";

        # Normalize headers before forwarding
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # Disable request buffering to prevent body manipulation
        proxy_request_buffering off;

        # Set strict timeouts to prevent hanging connections
        proxy_connect_timeout 5s;
        proxy_send_timeout 10s;
        proxy_read_timeout 10s;
    }
}

# Back-end server pool
upstream backend_servers {
    server 10.0.1.10:8080 max_fails=3 fail_timeout=30s;
    server 10.0.1.11:8080 max_fails=3 fail_timeout=30s;

    # Use least connections to distribute load
    least_conn;

    # Keep connections alive but with short timeout
    keepalive 32;
    keepalive_timeout 10s;
}

# Terraform configuration for AWS ALB with request smuggling protection

# Application Load Balancer
resource "aws_lb" "main" {
  name               = "secure-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = aws_subnet.public[*].id

  enable_deletion_protection = true
  enable_http2              = true  # Enable HTTP/2 to prevent smuggling
  enable_cross_zone_load_balancing = true

  drop_invalid_header_fields = true  # Critical: Drop malformed headers

  access_logs {
    bucket  = aws_s3_bucket.alb_logs.bucket
    enabled = true
  }

  tags = {
    Name        = "secure-alb"
    Environment = "production"
    Security    = "hardened"
  }
}

# HTTPS Listener with HTTP/2
resource "aws_lb_listener" "https" {
  load_balancer_arn = aws_lb.main.arn
  port              = "443"
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-TLS13-1-2-2021-06"  # TLS 1.2+
  certificate_arn   = aws_acm_certificate.main.arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app.arn
  }
}

# HTTP to HTTPS redirect
resource "aws_lb_listener" "http_redirect" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type = "redirect"
    redirect {
      port        = "443"
      protocol    = "HTTPS"
      status_code = "HTTP_301"
    }
  }
}

# Target Group with health checks
resource "aws_lb_target_group" "app" {
  name     = "app-tg"
  port     = 8080
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  # Connection settings to prevent smuggling
  deregistration_delay = 30

  health_check {
    enabled             = true
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 5
    interval            = 30
    path                = "/health"
    protocol            = "HTTP"
    matcher             = "200"
  }

  stickiness {
    type            = "lb_cookie"
    cookie_duration = 86400
    enabled         = true
  }

  tags = {
    Name = "app-target-group"
  }
}

# AWS WAF WebACL for request smuggling detection
resource "aws_wafv2_web_acl" "main" {
  name  = "request-smuggling-protection"
  scope = "REGIONAL"

  default_action {
    allow {}
  }

  # Rule 1: Block requests with both Content-Length and Transfer-Encoding
  rule {
    name     = "BlockDualHeaders"
    priority = 1

    action {
      block {
        custom_response {
          response_code = 400
        }
      }
    }

    statement {
      and_statement {
        statement {
          byte_match_statement {
            field_to_match {
              single_header {
                name = "content-length"
              }
            }
            positional_constraint = "EXACTLY"
            search_string         = ""
            text_transformation {
              priority = 0
              type     = "NONE"
            }
          }
        }
        statement {
          byte_match_statement {
            field_to_match {
              single_header {
                name = "transfer-encoding"
              }
            }
            positional_constraint = "EXACTLY"
            search_string         = "chunked"
            text_transformation {
              priority = 0
              type     = "LOWERCASE"
            }
          }
        }
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "BlockDualHeaders"
      sampled_requests_enabled   = true
    }
  }

  # Rule 2: AWS Managed Rules - Core Rule Set
  rule {
    name     = "AWS-AWSManagedRulesCommonRuleSet"
    priority = 10

    override_action {
      none {}
    }

    statement {
      managed_rule_group_statement {
        name        = "AWSManagedRulesCommonRuleSet"
        vendor_name = "AWS"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "AWSManagedRulesCommonRuleSetMetric"
      sampled_requests_enabled   = true
    }
  }

  # Rule 3: Block invalid chunked encoding patterns
  rule {
    name     = "BlockInvalidChunkedEncoding"
    priority = 2

    action {
      block {
        custom_response {
          response_code = 400
        }
      }
    }

    statement {
      regex_pattern_set_reference_statement {
        arn = aws_wafv2_regex_pattern_set.invalid_chunked.arn
        field_to_match {
          single_header {
            name = "transfer-encoding"
          }
        }
        text_transformation {
          priority = 0
          type     = "LOWERCASE"
        }
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "BlockInvalidChunkedEncoding"
      sampled_requests_enabled   = true
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "RequestSmugglingProtection"
    sampled_requests_enabled   = true
  }

  tags = {
    Name = "request-smuggling-waf"
  }
}

# Regex pattern for invalid chunked encoding
resource "aws_wafv2_regex_pattern_set" "invalid_chunked" {
  name  = "invalid-chunked-patterns"
  scope = "REGIONAL"

  regular_expression {
    regex_string = "chunked.*chunked"
  }
  regular_expression {
    regex_string = "chunked.+,"
  }
  regular_expression {
    regex_string = ",.+chunked"
  }

  tags = {
    Name = "invalid-chunked-patterns"
  }
}

# Associate WAF with ALB
resource "aws_wafv2_web_acl_association" "main" {
  resource_arn = aws_lb.main.arn
  web_acl_arn  = aws_wafv2_web_acl.main.arn
}

# CloudWatch Alarm for WAF blocks
resource "aws_cloudwatch_metric_alarm" "waf_blocks" {
  alarm_name          = "waf-request-smuggling-blocks"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "1"
  metric_name         = "BlockDualHeaders"
  namespace           = "AWS/WAFV2"
  period              = "300"
  statistic           = "Sum"
  threshold           = "10"
  alarm_description   = "Alert when WAF blocks more than 10 request smuggling attempts in 5 minutes"
  alarm_actions       = [aws_sns_topic.security_alerts.arn]

  dimensions = {
    WebACL = aws_wafv2_web_acl.main.name
    Region = data.aws_region.current.name
    Rule   = "BlockDualHeaders"
  }
}
